// v2 (audit items 2.1, 2.5, Day 5): trace_id, prev_campaigns injection, lower temperature.
// Prompt source: build/prompts/ad_drafting.md version ad_drafting.v2.
const property = $('Supabase: Get Property').first().json;
const prevCampaignsRaw = $('Supabase: Get Previous Campaigns').all().map(i => i.json);
const t0 = Date.now();
const traceId = (typeof crypto !== 'undefined' && crypto.randomUUID) ? crypto.randomUUID() : ('xxxxxxxx-xxxx-4xxx-yxxx-xxxxxxxxxxxx'.replace(/[xy]/g, c => { const r = Math.random()*16|0; const v = c==='x' ? r : (r&0x3|0x8); return v.toString(16); }));

// Compact prev campaigns into something the model can absorb without blowing context.
const prevCampaigns = prevCampaignsRaw
  .sort((a, b) => new Date(b.created_at || 0) - new Date(a.created_at || 0))
  .slice(0, 3)
  .map(c => ({ platform: c.platform, ad_copy: c.ad_copy, cpl_inr: c.cpl_inr, leads_generated: c.leads_generated }));

const hasHistory = prevCampaigns.length > 0;

const systemPrompt = "You are the Ad Agent for an Indian residential real estate sales platform. Given a property record AND optionally the most recent past campaigns for that property, draft platform-specific ad creatives that a marketing lead can review and publish.\n\nGround every claim ONLY in the provided property; do not invent prices, possession dates, or amenities. Use Indian conventions (lakhs/Cr; BHK; sqft).\n\nWhen PREVIOUS_CAMPAIGNS is provided: do NOT repeat headlines or hooks verbatim. Vary the angle (e.g., if past Meta lead with possession date, this draft leads with locality; if past lead with price, this leads with amenity stack). Acknowledge what already worked (high leads_generated) by keeping its tone, and avoid what underperformed.\n\nPlatform constraints:\n- meta: 1-2 punchy sentences, conversational, mobile-first, no emoji (only one at the end if natural). Up to 180 chars.\n- google: a 30-char headline AND a 90-char description, concatenated as 'HEADLINE | DESCRIPTION'. Factual, intent-matched.\n- portal: a 60-char headline AND a 150-char description, concatenated as 'HEADLINE | DESCRIPTION'. Specs-heavy, what-you-get focused.\n\nFor each platform also produce target_audience: a single sentence describing age band, household income, geo, and intent signals appropriate to that platform and that property's price tier.\n\nNEVER use these banned phrases (RERA Act §11 advertising-claim risk): 'guaranteed return', 'guaranteed appreciation', 'risk-free', 'assured returns', '100% safe', any specific percentage return promise.\n\nOutput a single JSON object with exactly these keys: { meta: { ad_copy, target_audience }, google: { ad_copy, target_audience }, portal: { ad_copy, target_audience }, novelty_note: 'one short sentence on what you varied vs past campaigns, or `first campaign for this property` if none' }. No prose, no markdown fences.";

const userPrompt = 'PROPERTY:\n' + JSON.stringify({
  project_name: property.project_name,
  developer: property.developer,
  city: property.city,
  locality: property.locality,
  config: property.config,
  price_min_lakhs: property.price_min_lakhs,
  price_max_lakhs: property.price_max_lakhs,
  possession_date: property.possession_date,
  highlights: property.highlights || [],
  amenities: (property.amenities || []).slice(0, 6)
}, null, 2) + (hasHistory
  ? ('\n\nPREVIOUS_CAMPAIGNS (most recent first):\n' + JSON.stringify(prevCampaigns, null, 2))
  : '\n\nPREVIOUS_CAMPAIGNS: none (this is the first campaign for this property).')
+ '\n\nDraft the 3 platform creatives. Return ONLY the JSON object.';

const geminiBody = JSON.stringify({
  systemInstruction: { parts: [{ text: systemPrompt }] },
  contents: [{ role: 'user', parts: [{ text: userPrompt }] }],
  generationConfig: { temperature: 0.2, responseMimeType: 'application/json' }
});

return [{ json: { property, geminiBody, traceId, promptStartedAt: t0, promptVersion: 'ad_drafting.v2', prevCampaignCount: prevCampaigns.length } }];

// v2 (audit item 2.5, Day 5): deterministic seed + trace_id + observability fields.
// Same property + same date returns the same simulated metrics across re-runs (demo reproducibility).
const ctx = $('Code: Build Ad Body').first().json;
const latencyMs = Math.max(0, Date.now() - (ctx.promptStartedAt || Date.now()));
const traceId = ctx.traceId;
const promptVersion = ctx.promptVersion;

const resp = $('Gemini: Draft Ad Copy').first().json;
const property = $('Supabase: Get Property').first().json;

let parsed = null;
try {
  const text = resp?.candidates?.[0]?.content?.parts?.[0]?.text || '';
  parsed = JSON.parse(text);
} catch (e) {
  return [{ json: { ok: false, error: 'Gemini parse failure: ' + e.message, traceId, latencyMs, promptVersion } }];
}

if (!parsed?.meta || !parsed?.google || !parsed?.portal) {
  return [{ json: { ok: false, error: 'Missing platform copies in Gemini output', got: parsed, traceId, latencyMs, promptVersion } }];
}

// v2: deterministic PRNG seeded by (property_id + date + platform). Same inputs → same metrics.
// Mulberry32 PRNG: tiny, deterministic, decent distribution.
function seedFromString(s) { let h = 2166136261 >>> 0; for (let i = 0; i < s.length; i++) { h ^= s.charCodeAt(i); h = Math.imul(h, 16777619); } return h >>> 0; }
function mulberry32(seed) { return function() { let t = (seed += 0x6D2B79F5); t = Math.imul(t ^ (t >>> 15), t | 1); t ^= t + Math.imul(t ^ (t >>> 7), t | 61); return ((t ^ (t >>> 14)) >>> 0) / 4294967296; }; }
const today = new Date().toISOString().slice(0, 10);

const midPrice = (Number(property.price_min_lakhs || 100) + Number(property.price_max_lakhs || 200)) / 2;
const tierMultiplier = midPrice < 100 ? 0.6 : midPrice < 250 ? 1.0 : 1.8;

function simulate(platform, budgetBase, cplLow, cplHigh) {
  const rnd = mulberry32(seedFromString(property.id + '|' + today + '|' + platform));
  const budget = Math.round(budgetBase * tierMultiplier * (0.85 + rnd() * 0.3));
  const cpl = Math.round(cplLow + rnd() * (cplHigh - cplLow));
  const leads = Math.max(20, Math.round(budget / cpl));
  const clicks = Math.round(leads * (8 + rnd() * 6));
  const impressions = Math.round(clicks * (35 + rnd() * 25));
  return { budget, cpl, leads, clicks, impressions };
}

const now = new Date().toISOString();
const campaignBase = `${property.project_name} ${now.slice(0, 10)}`;

const meta = simulate('Meta', 220000, 500, 1500);
const google = simulate('Google', 160000, 700, 1800);
const portal = simulate('Portal', 90000, 400, 900);

return [{
  json: {
    ok: true,
    traceId,
    promptVersion,
    latencyMs,
    modelUsed: 'gemini-2.5-flash',
    novelty_note: parsed.novelty_note || null,
    property_id: property.id,
    project_name: property.project_name,
    meta: {
      campaign_name: `${campaignBase} | Meta`,
      ad_copy: parsed.meta.ad_copy,
      target_audience: parsed.meta.target_audience,
      ...meta
    },
    google: {
      campaign_name: `${campaignBase} | Google`,
      ad_copy: parsed.google.ad_copy,
      target_audience: parsed.google.target_audience,
      ...google
    },
    portal: {
      campaign_name: `${campaignBase} | Portal`,
      ad_copy: parsed.portal.ad_copy,
      target_audience: parsed.portal.target_audience,
      ...portal
    }
  }
}];

// Build 3 sheet rows — one per channel (Meta, Google, Portal).
// Pulls campaign_id from each inserted row + creative fields from Parse & Simulate output.

const property = $('Supabase: Get Property').first().json;
const parsed = $('Code: Parse & Simulate').first().json;

const meta = $('Supabase: Insert Meta').first().json;
const google = $('Supabase: Insert Google').first().json;
const portal = $('Supabase: Insert Portal').first().json;

const now = new Date().toISOString();
const propertyName = property.project_name || property.name || '';
const agentVersion = parsed.prompt_version || parsed.promptVersion || 'ad_drafting.v2';

// Extract per-channel creative from parsed output. Pattern: parsed.channels.{meta,google,portal}.{headline, primary_text, cta, budget_inr}
const c = parsed.channels || {};
const m = c.meta || {};
const g = c.google || {};
const p = c.portal || {};

const rows = [
  {
    json: {
      created_at: now,
      campaign_id: meta.id || '',
      property_id: property.id || '',
      property_name: propertyName,
      channel: 'meta',
      status: meta.status || 'live',
      budget_inr: m.budget_inr || meta.budget_inr || '',
      headline: m.headline || meta.headline || '',
      primary_text: m.primary_text || meta.primary_text || '',
      cta: m.cta || meta.cta || '',
      agent_version: agentVersion
    }
  },
  {
    json: {
      created_at: now,
      campaign_id: google.id || '',
      property_id: property.id || '',
      property_name: propertyName,
      channel: 'google',
      status: google.status || 'live',
      budget_inr: g.budget_inr || google.budget_inr || '',
      headline: g.headline || google.headline || '',
      primary_text: g.primary_text || google.description || '',
      cta: g.cta || google.cta || '',
      agent_version: agentVersion
    }
  },
  {
    json: {
      created_at: now,
      campaign_id: portal.id || '',
      property_id: property.id || '',
      property_name: propertyName,
      channel: 'portal',
      status: portal.status || 'live',
      budget_inr: p.budget_inr || portal.budget_inr || '',
      headline: p.headline || portal.headline || '',
      primary_text: p.primary_text || portal.description || '',
      cta: p.cta || portal.cta || '',
      agent_version: agentVersion
    }
  }
];

return rows;
